// ============================================================
// Daily Summary Report Builder
// ============================================================
// Aggregates the day's attendance data into a formatted Slack
// message with key metrics, flags, and employee status.
// Outputs TWO items:
//   [0] = full daily report for #attendance
//   [1] = absent employee list for #absent
// ============================================================

const data = $input.first().json;
const employees = data.employees || [];
const date = data.date || new Date().toISOString().split('T')[0];

const total = employees.length;
const checkedIn = employees.filter(e => e.checked_in).length;
const checkedOut = employees.filter(e => e.checked_out).length;
const stillWorking = employees.filter(e => e.checked_in && !e.checked_out).length;
const onBreak = employees.filter(e => e.on_break).length;
const absent = employees.filter(e => !e.checked_in).length;
const lateArrivals = employees.filter(e => e.is_late);
const overtimeWorkers = employees.filter(e => Number(e.overtime_hours) > 0);
const undertimeWorkers = employees.filter(e => e.checked_out && Number(e.net_hours) < 8);
const breakViolations = employees.filter(e => e.break_violation);

let report = `*Daily Attendance Report — ${date}*\n`;
report += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;

report += `*Team Status*\n`;
report += `Total: ${total} | Checked In: ${checkedIn} | Checked Out: ${checkedOut}\n`;
report += `Still Working: ${stillWorking} | On Break: ${onBreak} | Absent: ${absent}\n\n`;

if (lateArrivals.length > 0) {
  report += `*Late Arrivals (${lateArrivals.length})*\n`;
  lateArrivals.forEach(e => {
    report += `  - ${e.name}: ${e.minutes_late} min late\n`;
  });
  report += `\n`;
}

if (overtimeWorkers.length > 0) {
  report += `*Overtime (${overtimeWorkers.length})*\n`;
  overtimeWorkers.forEach(e => {
    report += `  - ${e.name}: +${Number(e.overtime_hours).toFixed(1)}h OT\n`;
  });
  report += `\n`;
}

if (undertimeWorkers.length > 0) {
  report += `*Undertime (${undertimeWorkers.length})*\n`;
  undertimeWorkers.forEach(e => {
    report += `  - ${e.name}: ${Number(e.net_hours).toFixed(1)}h (${(8 - Number(e.net_hours)).toFixed(1)}h short)\n`;
  });
  report += `\n`;
}

if (breakViolations.length > 0) {
  report += `*Break Compliance Issues (${breakViolations.length})*\n`;
  breakViolations.forEach(e => {
    report += `  - ${e.name}: ${e.break_issue}\n`;
  });
  report += `\n`;
}

if (absent > 0) {
  const absentList = employees.filter(e => !e.checked_in);
  report += `*Absent (${absent})*\n`;
  absentList.forEach(e => {
    report += `  - ${e.name}${e.on_leave ? ' (on leave)' : ''}\n`;
  });
}

// Build absent list for #absent channel
const absentEmployees = employees.filter(e => !e.checked_in);
let absentReport = `*Absent Employees — ${date}*\n`;
absentReport += `━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;
if (absentEmployees.length === 0) {
  absentReport += `All employees checked in today.`;
} else {
  absentReport += `*${absentEmployees.length} employee(s) did not check in:*\n\n`;
  absentEmployees.forEach((e, i) => {
    absentReport += `${i + 1}. ${e.name}${e.on_leave ? ' (on leave)' : ''}\n`;
  });
}

return [
  { json: { report, date, _outputType: 'daily_report' } },
  { json: { report: absentReport, date, _outputType: 'absent_list' } }
];

// ============================================================
// Format Daily Divider Date
// ============================================================
// Generates a date string in PHT (UTC+8) for the daily divider.
// Uses manual UTC+8 offset (toLocaleString is unreliable on Vercel/n8n).
// ============================================================

const now = new Date();
const phtMs = now.getTime() + (8 * 60 * 60 * 1000);
const pht = new Date(phtMs);

const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'];

const dayName = days[pht.getUTCDay()];
const month = months[pht.getUTCMonth()];
const date = pht.getUTCDate();
const year = pht.getUTCFullYear();

const dividerText = `${month} ${date}, ${year} (${dayName})`;

return [{ json: { dividerText } }];
